function validate(args, output) {
    const s = args[0];
    if (!Array.isArray(output)) return false;
    function isValid(t) {
        let depth = 0;
        for (const ch of t) {
            if (ch === '(') depth++;
            else if (ch === ')') {
                depth--;
                if (depth < 0) return false;
            }
        }
        return depth === 0;
    }
    function minRemovals(t) {
        let left = 0, right = 0;
        for (const ch of t) {
            if (ch === '(') left++;
            else if (ch === ')') {
                if (left > 0) left--;
                else right++;
            }
        }
        return left + right;
    }
    const minRem = minRemovals(s);
    const targetLen = s.length - minRem;
    // Build correct set via BFS removing one char at a time
    let current = new Set([s]);
    let correct = null;
    for (let level = 0; level <= s.length; level++) {
        const valid = new Set();
        for (const t of current) if (isValid(t)) valid.add(t);
        if (valid.size > 0) { correct = valid; break; }
        const next = new Set();
        for (const t of current) {
            for (let i = 0; i < t.length; i++) {
                if (t[i] === '(' || t[i] === ')') {
                    next.add(t.slice(0, i) + t.slice(i + 1));
                }
            }
        }
        current = next;
    }
    if (!correct) correct = new Set(['']);
    const seen = new Set();
    for (const item of output) {
        if (typeof item !== 'string') return false;
        if (seen.has(item)) return false;
        seen.add(item);
        if (!isValid(item)) return false;
        if (item.length !== targetLen) return false;
        if (!correct.has(item)) return false;
    }
    return seen.size === correct.size;
}

