class Solution:
    def removeInvalidParentheses(self, s):
        from collections import deque
        visited = {s}
        queue = deque([s])
        found = []
        found_level = False
        while queue and not found_level:
            size = len(queue)
            for _ in range(size):
                curr = queue.popleft()
                depth = 0
                valid = True
                for ch in curr:
                    if ch == '(': depth += 1
                    elif ch == ')':
                        depth -= 1
                        if depth < 0: valid = False; break
                if valid and depth == 0:
                    found.append(curr)
                    found_level = True
                if not found_level:
                    for i in range(len(curr)):
                        if curr[i] not in '()':
                            continue
                        nxt = curr[:i] + curr[i+1:]
                        if nxt not in visited:
                            visited.add(nxt)
                            queue.append(nxt)
        return sorted(found)

